  ('elementary-8b44517b-moex-00867', 'elementary-8b44517b', 'elementary-8b44517b-moex-110-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '下列有關禁止性別歧視之論述，何者不符合性別工作平等法之規定？', '["雇主對求職者或受僱者之招募不得因性別或性傾向而有差別待遇，但工作性質僅適合特定性別者，不 在此限", "工作規則、勞動契約或團體協約若規定或事先約定受僱者有結婚、懷孕、分娩或育兒之情事時，應行 離職或留職停薪，該規定或約定之效力未定", "雇主對受僱者薪資之給付得基於年資、獎懲、績效或其他非因性別或性傾向因素之正當理由而為差別待遇", "雇主為受僱者舉辦或提供各項福利措施，不得因性別或性傾向而有差別待遇"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:34+00:00", "source_pdf_sha1": "252bd0a98402", "answer_pdf_sha1": "3e05bf291669", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00868', 'elementary-8b44517b', 'elementary-8b44517b-moex-110-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '受僱者於其配偶分娩時，依性別工作平等法之規定，雇主應給予幾日之陪產假？', '["3日", "5日", "7日", "10日"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:34+00:00", "source_pdf_sha1": "252bd0a98402", "answer_pdf_sha1": "3e05bf291669", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00869', 'elementary-8b44517b', 'elementary-8b44517b-moex-110-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '職業訓練法中所規定的職業訓練之實施，不包括下列何者？', '["身心障礙者訓練", "養成訓練", "進修訓練", "轉業訓練"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:34+00:00", "source_pdf_sha1": "252bd0a98402", "answer_pdf_sha1": "3e05bf291669", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00870', 'elementary-8b44517b', 'elementary-8b44517b-moex-110-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '下列何者非屬職工福利金條例中對於職工福利金之保障規定？', '["職工福利金不得沒收", "職工福利金有優先受清償之權", "因保管人之過失致職工福利金受損失時，應由提撥者負賠償責任", "工廠、礦場或其他企業組織因解散或受破產宣告而結束經營者，所提撥之職工福利金，應由職工福利 委員會妥議處理方式，陳報主管官署備查後發給職工"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:34+00:00", "source_pdf_sha1": "252bd0a98402", "answer_pdf_sha1": "3e05bf291669", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00871', 'elementary-8b44517b', 'elementary-8b44517b-moex-110-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '私立學校、團體及民營事業機構員工總人數在多少人以上時，必須進用具有就業能力之身心障礙者人數， 不得低於員工總人數百分之一且不得少於一人，否則應定期向所在地直轄市、縣（市）勞工主管機關之 身心障礙者就業基金繳納差額補助費？', '["34人", "50人", "67人", "100人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:34+00:00", "source_pdf_sha1": "252bd0a98402", "answer_pdf_sha1": "3e05bf291669", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
